// Arma el cuerpo JSON que espera Sinatura para crear el trabajo de firma.
// Combina los datos del documento/trabajador (SQL anterior) con la config del envío (body.firmaData).
const row = $json;
const fd = $('Execute Workflow Trigger').first().json.body.firmaData || {};
const doble = fd.modo_firmantes === 'doble';

const signers = [{
  email: fd.email_trabajador,
  name: row.nombre || 'Trabajador',
  surname: ((row.primer_apellido || '') + ' ' + (row.segundo_apellido || '')).trim() || '-',
  numberID: row.dni || ''
}];
if (doble && fd.email_segundo_firmante) {
  signers.push({ email: fd.email_segundo_firmante, name: 'Recursos Humanos', surname: 'Empresa', numberID: '' });
}

// Email del firmante segun el rol del cuadrito ('rrhh' -> 2.o firmante; resto -> trabajador).
const emailDe = (rol) => (rol === 'rrhh' ? fd.email_segundo_firmante : fd.email_trabajador);

// POSICIONES DE FIRMA.
// 1) Si el usuario las ubico en el editor visual (fd.posiciones), usamos esas: cada cuadrito
//    es una entrada de signatureSettings (se permiten varias por firmante). page es 1-indexado;
//    xo/yo/width/height ya vienen en % (0-90 / 5-100) acotados.
// 2) Si no vienen, respaldo: una firma por firmante al pie de la ULTIMA pagina.
let signatureSettings = [];
if (Array.isArray(fd.posiciones) && fd.posiciones.length) {
  signatureSettings = fd.posiciones
    .filter(p => p && (p.rol !== 'rrhh' || (doble && fd.email_segundo_firmante)))
    .map(p => ({
      signerEmail: emailDe(p.rol),
      page: p.page,
      xo: p.xo,
      yo: p.yo,
      width: p.width,
      height: p.height,
    }));
}
if (!signatureSettings.length) {
  // Respaldo por coordenadas. Sinatura: page es 1-indexado (1=primera, 0=TODAS).
  const pdfBin = Buffer.from(row.contenido_b64 || '', 'base64').toString('latin1');
  const counts = (pdfBin.match(/\/Count\s+(\d+)/g) || []).map(s => parseInt(s.replace(/\D/g, ''), 10));
  const ultimaPagina = counts.length ? Math.max(...counts) : 1;
  signatureSettings = [
    { signerEmail: fd.email_trabajador, page: ultimaPagina, xo: 52, yo: 78, width: 20, height: 9 }
  ];
  if (doble && fd.email_segundo_firmante) {
    signatureSettings.push({ signerEmail: fd.email_segundo_firmante, page: ultimaPagina, xo: 8, yo: 78, width: 20, height: 9 });
  }
}

const exp = new Date();
exp.setDate(exp.getDate() + 7); // caduca en 7 dias

const sinaturaBody = {
  document: row.contenido_b64,
  documentName: row.nombre_fichero || 'documento.pdf',
  description: 'Firma de documento de trabajador',
  signatureType: 'STANDARD',
  skipSignerMail: true,
  signers,
  signatureSettings,
  SignatureExpiryDate: exp.toISOString().slice(0, 10)
};

return [{ json: { sinaturaBody } }];

// Construye el/los correo(s) HTML de Sg Tech: el sobre (logo, colores, boton, pie) lo define este
// template; el contenido es el texto editable del modal (mensaje_correo).
// Con doble firmante emite UN item por persona y el nodo Outlook envia un correo por item:
//   trabajador -> signatureJobURLs[0]   |   RRHH (2do firmante) -> signatureJobURLs[1]
const trg = $('Execute Workflow Trigger').first().json.body.firmaData || {};
const mensaje = trg.mensaje_correo || 'Tienes un documento pendiente de firma.';
const docName = ($('Code: Armar petición Sinatura').first().json.sinaturaBody || {}).documentName || 'documento';
const urls = $('HTTP: Crear firma en Sinatura').first().json.signatureJobURLs || [];
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const cuerpo = esc(mensaje).replace(/\n/g, '<br>');
const buildHtml = (url) => `<!DOCTYPE html>
<html lang='es'><head><meta charset='UTF-8'><meta name='viewport' content='width=device-width, initial-scale=1.0'>
<style>@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap');</style></head>
<body style='margin:0;padding:0;background:#f4f5f9;font-family:Poppins,Segoe UI,Arial,sans-serif;'>
<table role='presentation' width='100%' cellpadding='0' cellspacing='0' style='background:#f4f5f9;padding:32px 0;'><tr><td align='center'>
<table role='presentation' width='600' cellpadding='0' cellspacing='0' style='width:600px;max-width:600px;background:#ffffff;border-radius:14px;overflow:hidden;box-shadow:0 4px 24px rgba(40,40,90,0.10);'>
<tr><td style='height:6px;background:linear-gradient(90deg,#5a4d9a,#55569e,#476fab,#3198bf,#23b4cd);font-size:0;line-height:0;'>&nbsp;</td></tr>
<tr><td align='center' style='padding:40px 40px 0;'><h1 style='margin:0;font-family:Poppins,Segoe UI,Arial,sans-serif;font-size:20px;font-weight:700;color:#5a4d9a;'>Solicitud de firma electrónica</h1></td></tr>
<tr><td style='padding:22px 44px 4px;font-family:Poppins,Segoe UI,Arial,sans-serif;font-size:15px;line-height:1.65;color:#3f3f55;'>${cuerpo}</td></tr>
<tr><td align='center' style='padding:24px 40px 8px;'><table role='presentation' cellpadding='0' cellspacing='0'><tr><td align='center' style='border-radius:10px;background:#476fab;background:linear-gradient(90deg,#5a4d9a,#476fab,#23b4cd);'><a href='${url}' target='_blank' style='display:inline-block;padding:14px 40px;font-family:Poppins,Segoe UI,Arial,sans-serif;font-size:15px;font-weight:600;color:#ffffff;text-decoration:none;border-radius:10px;'>Firmar documento</a></td></tr></table></td></tr>
<tr><td align='center' style='padding:4px 44px 26px;font-family:Poppins,Segoe UI,Arial,sans-serif;font-size:12px;line-height:1.5;color:#9aa0b4;'>Si el botón no funciona, copia y pega este enlace en tu navegador:<br><a href='${url}' target='_blank' style='color:#3198bf;word-break:break-all;'>${url}</a></td></tr>
<tr><td style='padding:20px 40px;background:#f7f8fc;border-top:1px solid #ecedf4;font-family:Poppins,Segoe UI,Arial,sans-serif;font-size:12px;line-height:1.6;color:#9aa0b4;text-align:center;'><strong style='color:#5a4d9a;'>Sg Tech</strong> · Departamento de Recursos Humanos</td></tr>
</table></td></tr></table></body></html>`;
const doble = trg.modo_firmantes === 'doble';
const destinatarios = [{ sendTo: trg.email_trabajador, url: urls[0] || '' }];
if (doble && trg.email_segundo_firmante) {
  destinatarios.push({ sendTo: trg.email_segundo_firmante, url: urls[1] || '' });
}
return destinatarios
  .filter((d) => d.sendTo)
  .map((d) => ({ json: { html: buildHtml(d.url), asunto: 'Solicitud de firma: ' + docName, sendTo: d.sendTo } }));

// Mapea el estado de Sinatura a nuestro estado interno y deduce qué firmas se hicieron.
// signaturaStatus principal: Ready | Signing | Completed | Expired | Declined | Error | Deleted | Cancelled
// signerStatusList: estado por firmante (el [0] es el trabajador, el [1] el 2.º firmante/RRHH).
const r = $json || {};
const st = r.signaturaStatus;
const signers = r.signerStatusList || [];
const trabajadorFirmado = !!(signers[0] && signers[0].signaturaStatus === 'Completed');
const rrhhFirmado = !!(signers[1] && signers[1].signaturaStatus === 'Completed');

let nuevoEstado = 'EN_SINATURA';
let motivo = null;
let completado = false;
switch (st) {
  case 'Completed': nuevoEstado = 'COMPLETADO'; completado = true; break;
  case 'Signing':
  case 'Ready':     nuevoEstado = 'EN_SINATURA'; break;
  case 'Declined':  nuevoEstado = 'RECHAZADO'; motivo = 'Rechazado por el firmante'; break;
  case 'Expired':   nuevoEstado = 'CANCELADO'; motivo = 'El enlace de firma caducó'; break;
  case 'Cancelled': nuevoEstado = 'CANCELADO'; motivo = 'Cancelado en Sinatura'; break;
  case 'Deleted':   nuevoEstado = 'CANCELADO'; motivo = 'Eliminado en Sinatura'; break;
  case 'Error':     nuevoEstado = 'CANCELADO'; motivo = 'Error en el proceso de firma'; break;
  default:          nuevoEstado = 'EN_SINATURA';
}
return [{ json: { nuevoEstado, completado, motivo, trabajadorFirmado, rrhhFirmado } }];
